INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027efee3c98b0941765c83', '本来对老酒店期望不大，但花园酒店完全给了我一个意外惊喜！虽然因台风外面风大雨大，但呆在酒店一点也不闷：花园酒店博物馆的讲解，让我对酒店这个行业对中国酒店以及花园酒店的起源发展有了大概的了解，很幸运得到礼宾部金钥匙员工Tim陈一个多小时的陪伴及介绍，打卡酒店26个打卡点，对整个花园酒店有了更加深刻的印象。下午收到来自酒店的下午茶甜点和手写问候便签，让人意外又感动！早上在瀑布餐厅早餐，员工无论客人多工作量大，都注意到每个客人的需求，主动提出帮我们照相，虽然花园酒店是一家38年的老酒店，但硬件软件真的无愧于全国仅有三家白金五星酒店称号！我们刚住过香港东方文华酒店文华阁，花园的服务完全可以与之媲美，甚至有过之而无不及！', '["https://dimg04.c-ctrip.com/images/0234h12000c3cv4hg9CDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000c3cv5xr6E49_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000c3cv9ldC0E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000c3d09ew1F00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000c3d0aieCEA1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-08', '红棉双床套房', '套房', '家庭亲子', 309, 0, 5, 10, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027efee3c98b0941765c84', '大堂宽敞气派，却没有供客人等候的休息区；
房间价格不低，但设施简陋，卫生间马桶和淋雨区共用一扇门，非常鸡肋，前所未见；
客房打扫人员不专业，不按时提供免费饮用水，客人要求提供后还声称要收费的。对不起，我可没有说要依云的水。房间打扫完地面依旧很脏，地上还可见头发，黑点和不知明污渍。
前台服务人员不尽责，反馈了客房问题后，没有后续跟踪，等到离店后有电话询问入住体验。如真想改进，应该在入住期间询问才更有意义吧，更何况我是在入住过程中提出了问题的。
无论设施与服务，硬件和软件，都对不起老牌五星级酒店的称号。
服务行业靠的得就是服务与口碑，也许你们不缺客人，但客人也有很多酒店可以去选择！', '["https://dimg04.c-ctrip.com/images/0232212000bofr4cbD6D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000bofv56514E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000bofsqh57116_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-07-17', '花园双床房', '双床房', '家庭亲子', 292, 2, 3, 9, '["房间设施","客房服务","前台服务"]'::jsonb, '房间设施', '客房服务', '前台服务'),
('68027efee3c98b0941765c85', '老牌五星酒店，重新装修，设施齐全，环境优美，卫生干净整洁，城市中心，出行方便，服务很好。早餐很好、行政酒廊的下午茶、欢乐时光很棒，工作人员Carrie.Yuki.shirleg服务态度热情周到', '["https://dimg04.c-ctrip.com/images/0235s12000bpcpvjhB6A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000bpcjkiy6592_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000bpchi6453A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-20', '花园双床房', '双床房', '家庭亲子', 96, 1, 17, 7, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68027efee3c98b0941765c86', '慕名而来，想试试白金五星酒店，进房间有小小惊喜，但用厕所时发现抽风机不工作，早餐选了荔湾亭吃发现不如头一晚住的三星，说实话早餐太差劲了，期望值大打折扣，服务也一般。', '["https://dimg04.c-ctrip.com/images/0236s12000bui4spc2B58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000buhwqo359D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000buhyq7m2B43_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-08-07', '花园双床房', '双床房', '家庭亲子', 82, 1, 5, 7, '["餐饮设施","房间设施","整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度'),
('68027efee3c98b0941765c87', '1. ?? 广州花园酒店，一处让人心生花开的住宿胜地！服务??????????，环境???令人陶醉，餐饮美味可口???。这里的员工热情周到，让你感受到家的温馨和舒适。强烈推荐给所有寻找完美住宿体验的朋友们！?

2. ?? 广州花园酒店，一场花样满满的入住之旅！从入门到退房，无一不体现着专业与贴心。房间整洁舒适，设施一应俱全??。而且酒店周边景点众多，交通便利??。在这里度过的时光成为了我美好回忆的一部分。??

3. ?? 广州花园酒店，绝对是一处花花世界！入住期间，每一个细节都散发着品质和温馨。从大堂到客房，无处不体现出酒店对细节的追求。而且服务人员态度友好，亲切有礼??。真心感谢酒店为我们提供了一段美好的旅行时光！??

4. ?? 广州花园酒店，是花好月圆的理想住所！酒店独具特色的花园环境让人仿佛置身于童话世界?。设施设备一流，床铺舒适如云??。此外，餐厅的美食更是令人垂涎三尺。期待再次光临这个让人心醉的花园天堂！??

5. ?? 广州花园酒店，真是一座难以忘怀的花海！入住期间，我仿佛成为了花园中的一朵鲜花??。每一次与员工们的交流都给予我温暖和安心感。酒店的设施也超乎想象，简直就是一座繁华之中的绿洲??。我已经迫不及待要再次回到这个温馨的花园！??

特别鸣谢Grollian前台接待，特别温馨特别有笑容??', '["https://dimg04.c-ctrip.com/images/0236z12000c2g32l324DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000c2g2je37F5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000c2g61xz75C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000c2fr7zy05A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000c2g3dyk99B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-04', '红棉双床套房', '套房', '家庭亲子', 568, 0, 6, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027f09e3c98b0941765c88', '有历史的酒店，服务和餐饮很好，环境一流', '["https://dimg04.c-ctrip.com/images/0230912000cn7jz5e64D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000cn7f4at9AD4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-27', '红棉大床套房', '套房', '家庭亲子', 19, 0, 31, 5, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027f09e3c98b0941765c89', '酒店给升级了套房，服务态度很到位，酒店里有两家米其林一星和二星餐厅，还有两家米其林推介餐厅。一楼瀑布西餐厅早餐很棒！二楼喝下午茶服务细致，不用出酒店就达到了吃在广州的目的', '["https://dimg04.c-ctrip.com/images/0236n12000bqz5q5w2464_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000bqyear6D4EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000bqyne78B96C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000bqz0ok9A448_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000bqynw92D05B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000bqyuegyDA58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000bqyo5ulBA8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000bqykgjfF58A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000bqyv5vzCA26_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-26', '花园双床房', '双床房', '家庭亲子', 85, 0, 20, 9, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027f09e3c98b0941765c8a', '住花园酒店似乎成了每次到广州的习惯，但这次的住宿体验实在不能跟星级酒店对上号。第一次安排的房间厕所没有冲水，跟前台反映后换了另外一间。晚上洗脸，洗手盆水龙头一开水，水会往外弄到周围都湿，这个也很无语。本来这么小的房间就没地方放浴缸，但是硬把淋浴间弄成一个正方形浴缸，进去洗澡要跨过浴缸边，我164的身高跨过浴缸边都觉得危险，以后到广州应该不会住这里了。', '["https://dimg04.c-ctrip.com/images/0233e12000bv4xh6eAF86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000bv4utzk1710_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000bv55o1m7F41_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000bv4zise617B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000bv53n8u236C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-08-09', '花园大床房', '大床房', '家庭亲子', 176, 1, 5, 9, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027f09e3c98b0941765c8b', '老牌五星级酒店，够气派。', '["https://dimg04.c-ctrip.com/images/0231l12000cyoswznCE02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000cyot53p9592_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000cyot6qj29AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000cyoswzv561E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-17', '城央绿意双床房', '双床房', '情侣出游', 12, 0, 37, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027f09e3c98b0941765c8c', '这是目前为止住到过的五星酒店落差最大的一次，相比较于大堂的富丽堂皇，酒店房间真的可以用陋室来形容，跟快捷酒店都没得比，工作人员服务很好，这个值得肯定，但是房间又小设备又差，房间没法开窗里面异味很大，闻着很不舒服；浴缸和房间隔断是通透且很mini一块，洗手间和淋浴房真的小的可怜，坐便我老公185身高坐下去膝盖直接顶住玻璃隔墙，根本没法坐；最震撼的是，房间里面的灯带居然都是随意挂下来的，有个床头柜下面的灯带都着地的，隔壁就是洗手台和浴缸，要是水满过来一点，难道不会触电吗？隔壁在修地铁，到晚上11点了还是咚咚咚跟地震一样吵。', '["https://dimg04.c-ctrip.com/images/0233p12000boc49t4C0CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000bocehsm2EAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000bocf0q0B0B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000boc9eiuEB84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000boc9tlrC6D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000bocbrdpD426_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-07-17', '花园大床房', '大床房', '家庭亲子', 262, 5, 15, 9, '["房间设施","安静程度","卫生状况"]'::jsonb, '房间设施', '安静程度', '卫生状况'),
('68027f09e3c98b0941765c8d', '扂间干净卫生，装修布局舒服。环境优美，餐厅菜品丰富，味道不错。服务员热情大方，办理入住高效快捷。令人非常感觉舒服的酒店。下次还会入住。', '["https://dimg04.c-ctrip.com/images/0231312000c274uwhAC64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000c273utk91AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000c26zbvp8B01_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '花园双床房', '双床房', '家庭亲子', 67, 0, 6, 7, '["整体满意度","卫生状况","退房/入住效率"]'::jsonb, '整体满意度', '卫生状况', '退房/入住效率'),
('68027f09e3c98b0941765c8e', '房间很干净，工作人员服务态度很好很热情，特别是小华，很热心负责。春节期间酒店还有很多活动，舞狮很精彩。', '["https://dimg04.c-ctrip.com/images/0230g12000i6s5zwq27FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000i6sqhz5E457_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000i6t9sjmF753_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-31', '城央绿意双床房', '双床房', '家庭亲子', 51, 0, 1, 7, '["卫生状况","前台服务","整体满意度"]'::jsonb, '卫生状况', '前台服务', '整体满意度'),
('68027f09e3c98b0941765c8f', '超级不好的入住体验 1双床房的设计简直是反人类，淋浴区同浴缸合二为一，出入都需要跨过大概40公分高的浴缸边缘，如果有行动不便的或者小孩简直是硬伤，2卫生间，冲凉房与床之间没有遮挡，完全没有私隐可言3早上8点停水，事先没有通知，游泳后没有水冲凉，打电话问回复逐步恢复中（预计1小时后），可以提供瓶装水或者职员带去公寓楼冲凉4房间内电热水壶漏水，存在严重安全隐患，致电客房服务，回复送一个电热水壶过来，半小时都不见人影送过来5到一楼hsd咖啡阁，吃早餐，没有滑蛋配芦笋，改成煎蛋卷，需要退回10差价，当场问了服务员会有主管过来退单，然后重新收钱，我们至少坐了半小时，然后忘记了离开酒店也没有人主动联系我们，需要事后打电话再次询问才解决问题（不是多少钱的问题，是服务态度问题），这次真的住到一肚火，以后都不会再入住', '["https://dimg04.c-ctrip.com/images/0233s12000bmi6nr20F8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000bmi3bz0810C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000bmi6csgE2CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-07-10', '花园双床房', '双床房', '家庭亲子', 354, 1, 9, 9, '["房间设施","客房服务","整体满意度"]'::jsonb, '房间设施', '客房服务', '整体满意度'),
('68027f09e3c98b0941765c90', '花园酒店不愧是老牌五星，地理位置好，出门就是地铁站，服务周到，很多中东航空公司的乘务人员也下榻在这边，酒店内还有两家米其林餐厅，餐饮非常方便。城市酒店瀑布和博物馆非常惊喜！到的比较早，房间未打扫好，被升级了套房。值得一提的是，酒店茶包是TWG。下次来广州一定还会入住！', '["https://dimg04.c-ctrip.com/images/0234y12000bmsvh0eC961_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000bmt07mk17CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-11', '红棉双床套房', '套房', '家庭亲子', 134, 1, 4, 9, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('68027f09e3c98b0941765c91', '老牌的酒店，名头很大！前台入住登记排队至少要半个小时以上，整个大堂吵吵闹闹的，就像菜市场一样！早餐也要拿号排队，排了半个多小时，还排不到，只好放弃了！出去吃路边摊。估计再排下去就直接吃中午饭了。晕??晕??晕', '["https://dimg04.c-ctrip.com/images/0230l12000bm60urp5CB8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000bm5u84k9CF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000bm5u8o214AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000bm6058u8D42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000bm60c1c6D0D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-07-09', '花园大床房', '大床房', '情侣出游', 104, 1, 48, 8, '["前台服务","退房/入住效率","安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度'),
('68027f14e3c98b0941765c92', '这次入住体验很满意，酒店大堂很漂亮，?还有后花园跟博物馆，可以散散步，服务也很满意??，表扬kamille和maney 。', '["https://dimg04.c-ctrip.com/images/0233712000c4kcfadE143_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000c4ki054437D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000c4kfbxy6ACD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-13', '花园大床房', '大床房', '家庭亲子', 61, 0, 1, 7, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027f14e3c98b0941765c93', '一直很喜欢花园酒店，人气旺，服务好，有花园，有餐厅，嫩桑拿，能游泳，有品位，月饼也好吃，私密性也好！', '["https://dimg04.c-ctrip.com/images/0232p12000c8653qz4BAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000c8651200AA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000c8656dvC26A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000c864xno68E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000c864syf8782_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-23', '花园大床房', '大床房', '商务出差', 50, 0, 3, 7, '["公共设施","餐饮设施","整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度'),
('68027f14e3c98b0941765c94', '位置好，环境好，商务出行优选

酒店服务也好，没毛病

红棉套房，性价比超高，住过三次了

酒店人满为患，生意超好，太热闹，喜欢安静的不推荐.', '["https://dimg04.c-ctrip.com/images/0234d12000c4z3tws03E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000c4yr77i06CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000c4ymzc323EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000c4z45ou23D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000c4yyfvl9223_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-14', '红棉大床套房', '套房', '商务出差', 71, 0, 37, 6, '["性价比","整体满意度","安静程度"]'::jsonb, '性价比', '整体满意度', '安静程度'),
('68027f14e3c98b0941765c95', '客房服务非常好，早餐需要提高哦！', '["https://dimg04.c-ctrip.com/images/0237212000cnpdwyv0D67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000cnpea9j175D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000cnpglnu6C4F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-11-30', '花园双床房', '双床房', '独自旅行', 16, 0, 6, 4, '["客房服务","餐饮设施"]'::jsonb, '客房服务', '餐饮设施', NULL),
('68027f14e3c98b0941765c96', '设施：一进门，整个震撼，不愧为全国仅有的三个铂金五星级酒店之一
卫生：一尘不染的状态
环境：典型的岭南建筑特色，办理前台是红楼梦壁画
服务：排队办入住，送了荔枝饮、每房送了花园酒店的主题公仔
早餐:太丰盛了，很用心的早餐种草了纯果汁，京东买了，10元一瓶，厉害了
双人自助晚餐-瀑布餐厅:太好吃了，芝士扇贝、海参、生蚝，太多好吃的', '["https://dimg04.c-ctrip.com/images/0230z12000c0x7x670018_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000c0xbhfkB5CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000c0xcmqjCF32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-29', '花园双床房', '双床房', '家庭亲子', 165, 0, 5, 9, '["整体满意度","餐饮设施","卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况'),
('68027f14e3c98b0941765c97', '花园真的是宝藏酒店  瀑布餐厅的晚餐也很棒  服务很周到 地铁站出门就是  后面的街区也很好逛    非常满意', '["https://dimg04.c-ctrip.com/images/0233d12000c5z6pw862B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000c5z6o8wCDC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000c5zb22q2DFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000c5z9414B215_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000c5z5jjeB78D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-17', '花园大床房', '大床房', '家庭亲子', 55, 0, 30, 7, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027f14e3c98b0941765c98', '我真的一般不差评，因为红眼航班到酒店办理入住已经快凌晨一点半了，告诉我原本预定的房间没了，升级了传说中的“套房”（跟楼下提供的差评图片是一间），两点到房间水龙头就坏了，修到三点，没修好，孩子三点半才睡觉，早上九点被工地的声音吵醒。被子潮湿，睡的身上痒，淋浴间和马桶旧的程度无法想象，我们全家都没高兴洗澡。同行还有我的两位弟弟，二十几岁的高个男生一样r没双床房了让睡大床房，说免费加床，但据我弟弟反馈加床翻身就掉的那种。非常差的体验，好在携程积极解决，第二天第一时间给我换到了预定的房型。最后酒店给了一份欧舒丹的小样洗护套装表示道歉，感谢但心里面并不接受。本次广州行因为这酒店的第一晚一点体验感都没有。劝大家碰到相同情况一定要拒绝传说中的升级。', '["https://dimg04.c-ctrip.com/images/0230h12000bmj6uhz21DD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-07-11', '红棉双床套房', '套房', '家庭亲子', 321, 2, 13, 9, '["房间设施","安静程度","退房/入住效率"]'::jsonb, '房间设施', '安静程度', '退房/入住效率'),
('68027f14e3c98b0941765c99', '停车方便，而且门口就有地铁。一进门口就觉得很气派～酒店还有很多外国友人入住。排队办理入住的时候服务员会送上一小杯冰沙饮料给你消消暑。
    前台的帅哥见我们是情侣，还贴心的送了几朵花给我们，入住还送了一只小玩偶。
    自助晚餐人不多，但是质量十分好，三文鱼虎虾生蚝随便拿，还有鲍鱼什么的，总体十分满意??', '["https://dimg04.c-ctrip.com/images/0231v12000caf0d9zC61B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000caf1ohpF67A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000cafdrgiFEBD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000caexm648BF6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000cafcjy5DEA0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000caf9mvs20AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-30', '花园大床房', '大床房', '情侣出游', 155, 0, 3, 8, '["前台服务","交通便利性","餐饮设施"]'::jsonb, '前台服务', '交通便利性', '餐饮设施'),
('68027f14e3c98b0941765c9a', '首先大堂很富丽堂皇  香水味很浓 放间比较小 很闷。外面在施工 很吵 ！服务一级棒 ！餐厅 一楼西餐 二楼中餐  （带早餐的）都不是很丰富 。一楼一般情况下要排队。二楼餐厅不用排队环境不错??我住的三天都是。酒店的紧身房游泳馆??。房间还是比较旧。一楼的甜点咖啡屋值得去坐一坐', '["https://dimg04.c-ctrip.com/images/0231a12000bmai8427C06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000bmat5jr9B69_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000bmaxwuy3B5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000bmapx250541_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000bmapwv7FB16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000bmaq27f1436_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000bmayogj272D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-07-10', '花园双床房', '双床房', '独自旅行', 138, 2, 12, 7, '["安静程度","餐饮设施","整体满意度"]'::jsonb, '安静程度', '餐饮设施', '整体满意度'),
('68027f14e3c98b0941765c9b', '房间非常好，出行也方便，酒店里面外国人特别多，还升级了房间，感觉特别好，只怪自己买的劵太少了，不然真的还想再来。', '["https://dimg04.c-ctrip.com/images/0233912000c3s0dy2DD03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000c3s41nu5921_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000c3rxo816CFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000c3rw2y17830_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000c3s1rd4C1CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-10', '红棉双床套房', '套房', '家庭亲子', 56, 0, 15, 5, '["整体满意度","交通便利性","房间设施"]'::jsonb, '整体满意度', '交通便利性', '房间设施'),
('68027f20e3c98b0941765c9c', '非常棒的酒店 服务超级好 下次还来！
位置也很好 浴缸也有帮忙再消毒
早餐和下午茶都很不错 非常值得来住一次
还送了很多伴手礼
还有Kamille,niki两个小姐姐特别nice??', '["https://dimg04.c-ctrip.com/images/0232r12000br3n03i6976_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000br3gw0p1220_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000br3jlyjEABD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000br3odzn0502_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000br3go7y30D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000br3jzfm3284_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000br3i2743997_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000br3n99bFDF9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-26', '花园大床房', '大床房', '其他', 91, 0, 1, 6, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027f20e3c98b0941765c9d', '房间设施稍显陈旧，桃园馆名不符实。
交通方便，服务热情周到，花园瀑布令人惊艳，的确是闹市里的桃花源。
非常喜欢荔湾厅的菜品和热情服务。', '["https://dimg04.c-ctrip.com/images/0234j12000bygysn522BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000byhacybC529_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000byh1cf373BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000byh9tew3080_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000byh0zb6E275_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000byh54g26782_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000byh59gp9CD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000byh3qkd32D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000byh7pna5AAD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-08-20', '红棉大床套房', '套房', '情侣出游', 67, 0, 8, 7, '["房间设施","交通便利性","整体满意度"]'::jsonb, '房间设施', '交通便利性', '整体满意度'),
('68027f20e3c98b0941765c9e', '这次送孩子来中大上学，入住久闻大名的花园酒店，服务、餐饮、设施都很满意。唯一一点建议，就是房间的被子有点厚了，半夜热的出汗。', '["https://dimg04.c-ctrip.com/images/0232t12000c1j5jcf9801_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000c1j32buA5C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000c1j28ac963A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000c1ja42w3B78_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-31', '红棉双床套房', '套房', '家庭亲子', 62, 0, 2, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027f20e3c98b0941765c9f', '绝对超预期的感受。

首先一进门，就有白衣男生主动帮忙拿行李送至大堂。
接着粉衣女生开始为我们引导办理入住。

这次为我们办理入住的Tony很超级nice，因为有小朋友，帮我们其中一间大床房免费升级了套房。另外一件房也安排在了隔壁，最后也告知了酒店边上在修地铁，晚上睡觉会有噪音（啊，确实挺噪的?? 感觉是24小时在施工，就是中午和大半夜会消停点，如果是睡觉质量很浅的人要遭罪了）

酒店设施及清洁度都很高，唯一不足的是没有智能马桶（每天帮忙打扫的工作人员都超有礼貌，任何一位都会好好和我们打招呼，也会及时解决一些住宿问题）

4楼的露天泳池是最爱，那么热的天，非常适合带小朋友上午去释放能量（前台帮忙登记的眼镜男生也热心）

酒店的自助早餐相对其他而言，就很soso了，选择不多，纯属可以看看餐厅外的瀑布，不过室外花园真的很漂亮。

酒店位置出行地铁很方便，出门就是五号线淘金站，但是这个线路去一些景点无法直达，基本都是要换乘就是。

最后退宿的时候，大堂粉衣女生Rain做事也很效率，排队的人有些多，就主动一一询问需求及赠送了小礼品。

再次感谢酒店每位工作人员，此次入住体验超级棒，长辈小孩都很开心。', '["https://dimg04.c-ctrip.com/images/0232912000blkxvjpF9A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000blktsis57B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000blkykco8F7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-07', '花园大床房', '大床房', '家庭亲子', 503, 0, 4, 9, '["前台服务","整体满意度","安静程度"]'::jsonb, '前台服务', '整体满意度', '安静程度'),
('68027f20e3c98b0941765ca0', '本次带小孩入住，非常满意   整个酒店的环境  很惊艳，尤其是瀑布花园和餐厅，非常棒。', '["https://dimg04.c-ctrip.com/images/0235d12000cagxccb02D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000cah2my998A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000cah0rgkF29F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-30', '花园双床房', '双床房', '朋友出游', 43, 0, 35, 6, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027f20e3c98b0941765ca1', '酒店位置非常好，就在淘金路地铁站上来转弯即可到达，我们从顺德乘地铁直接来到酒店，酒店大堂一片奢华的景象，非常豪华，前台办理入住很快，酒店也很贴心，提早开了空调，在炎热夏天进入房间就能感受舒适的环境；酒店有一个后花园可以散步，有瀑布和小桥流水还有各种花草，非常适合拍照留念，下次去广州还会选择入住，五星好评；', '["https://dimg04.c-ctrip.com/images/0233k12000bt6qwm7E02D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000bt6srf9EA95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000bt6x76h9E60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000bt6wq3jB390_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000bt6tjko883B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000bt6l1plBC3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000bt6s0jm4ECB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000bt6w303F475_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000bt6qm0k4648_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-02', '花园大床房', '大床房', '家庭亲子', 153, 0, 17, 9, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027f20e3c98b0941765ca2', '感谢前台Niki的热心安排免费升级房型，不愧是老牌的酒店，地理环境服务超棒，也感谢大堂的rain，考虑到我们是晚上18:00的回家航班，免费帮我们延到14:00后退房，让我们的整个广州旅途没有任何的疲劳感。', '["https://dimg04.c-ctrip.com/images/0231612000cbkcudc8477_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000cbkcz7u87B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000cbkcus5FDE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000cbkczz0959E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-03', '红棉双床套房', '套房', '家庭亲子', 103, 0, 2, 9, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68027f20e3c98b0941765ca3', '酒店大堂很气派，地理位置很好，离各个景点都不远，门口就是淘金地铁站，打车也很方便，附近有广州酒家，点都德，陶陶居，酒店还有室外泳池，8个电梯，上下楼都不用等，花园很美，有瀑布，锦鲤看到人都会游过来，我们买了一点切片面包喂，孩子们玩得很开心', '["https://dimg04.c-ctrip.com/images/0231812000bmpq6jn6961_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000bmpx5qoE93C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000bmpsvn1811C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000bmpso66F7A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000bmq0bws8271_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000bmpujykAB05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000bmpuztt3048_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000bmpy1zz7C04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000bmpvkncD399_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-11', '花园大床房', '大床房', '家庭亲子', 119, 1, 7, 9, '["交通便利性","周边配套","公共设施"]'::jsonb, '交通便利性', '周边配套', '公共设施'),
('68027f20e3c98b0941765ca4', '作为白金五星酒店
设施：新
卫生：非常好
服务：非常好，笑脸迎人
这次的套餐非常值，而且参观了花园酒店博物馆，涨见识', '["https://dimg04.c-ctrip.com/images/0230112000c2449l070DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000c23x58m8E5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000c241qzsC1C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000c23ryxm9651_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '红棉大床套房', '套房', '家庭亲子', 58, 0, 3, 7, '["整体满意度","性价比","卫生状况"]'::jsonb, '整体满意度', '性价比', '卫生状况'),
('68027f20e3c98b0941765ca5', '办理入住时，前台可能看到了我之前的入住记录，马上说了“欢迎回来”还送了太太与女儿康乃馨，瞬间感觉很温馨。服务一如既往的好。花园酒店是我去广州的首选酒店之一', '["https://dimg04.c-ctrip.com/images/0235u12000btkb2rj30C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-03', '花园双床房', '双床房', '家庭亲子', 77, 0, 3, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027f2be3c98b0941765ca6', '给领导定的房间，反馈还不错', '["https://dimg04.c-ctrip.com/images/0232712000cnotweiDBCB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000cnouo7z66B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-30', '花园大床房', '大床房', '商务出差', 13, 0, 31, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027f2be3c98b0941765ca7', '环境优美 非常好??', '["https://dimg04.c-ctrip.com/images/0236u12000cp7vz01379D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000cp7wsvg8541_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000cp7wp3q440D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-08', '城央绿意大床房', '大床房', '商务出差', 10, 0, 6, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027f2be3c98b0941765ca8', '这次在花园一共住了九晚，应该是可以评论一下了。酒店位置很好找，就在5号地铁出口大约二十米处，酒店地处老城中心，周边美食众多，何况酒店本身就包含了几个米其林餐厅，这几个餐厅环境和品质也是相当不错。作为白金五星酒店，酒店服务是非常好，只是酒店确实年代久，设施有些老旧，甚至房间如其他客人提到的有点味道。而且，靠马路这边晚上施工，确实影响休息。有点遗憾的是连住九天，酒店也没给升级房间。感谢退房时，前台Gillian给与的帮助，态度认真负责。
如果再来广州，考虑再次入住。', '["https://dimg04.c-ctrip.com/images/0235f12000cukbmz9FF3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cuk8h2z7034_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000cukcli972F2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-02', '花园双床房', '双床房', '家庭亲子', 233, 0, 6, 9, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027f2be3c98b0941765ca9', '千里迢迢送孩子来广州上大学，虽然孩子的校区在番禺，但还是选择了广州花园酒店。
花园酒店让我觉得很惊艳，是我在国内住过的最满意的一家酒店了！感谢办理入住手续的前台
美女Jocea看到我们一家四口入住，帮忙升级行政套房，感谢大堂服务美女Rain帮忙解决小女儿的早餐！美在花园酒店，美在广州羊城！', '["https://dimg04.c-ctrip.com/images/0235812000c1yj7581566_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000c1ynyvrF155_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000c1yqro396DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000c1ypocs4399_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-02', '花园双床房', '双床房', '家庭亲子', 145, 0, 1, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027f2be3c98b0941765caa', '房间很干净！而且免费帮我升级了房型 还送了小甜点和小礼品 服务超级贴心 提前一天打电话询问需要什么房型 超级棒', '["https://dimg04.c-ctrip.com/images/0237212000c2grrvw1B08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000c2gu6qg5A7D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-04', '花园双床房', '双床房', '商务出差', 55, 0, 2, 8, '["客房服务","整体满意度","卫生状况"]'::jsonb, '客房服务', '整体满意度', '卫生状况'),
('68027f2be3c98b0941765cab', '酒店交通便利，在住期间提供免费停车服务，前台接待服务态度很好，房间干净整洁。', '["https://dimg04.c-ctrip.com/images/0235l12000co8cyoz3BA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000co898n6B8BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000co8hi5g45D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-03', '花园大床房', '大床房', '情侣出游', 38, 0, 9, 7, '["交通便利性","前台服务","卫生状况"]'::jsonb, '交通便利性', '前台服务', '卫生状况'),
('68027f2be3c98b0941765cac', '第二次入住了，还是会被花园酒店美到～
工作人员Viria很热情，有问必答，还帮我们升级了房间～
这次体验了瀑布餐厅的早餐，景色没话说，食物种类虽然不算很多，但味道都还不错。
酒店的地理位置也很棒，到哪都方便，下次还会考虑入住～', '["https://dimg04.c-ctrip.com/images/0235p12000c3w9f4z7B99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000c3wc8jpD898_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000c3w97is7C03_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-11', '花园大床房', '大床房', '家庭亲子', 113, 0, 5, 8, '["整体满意度","前台服务","交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性'),
('68027f2be3c98b0941765cad', '除了泳池围蔽没体验到泳池，其他都挺好的，
房间很大，也很有岭南特色，会推荐给第一次来广州的朋友们。早餐种类不是那么的丰富，', '["https://dimg04.c-ctrip.com/images/0233n12000bzfxivm889D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000bzfv4ex477B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000bzfv50k398C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-08-23', '花园大床房', '大床房', '情侣出游', 61, 0, 12, 6, '["公共设施","整体满意度","餐饮设施"]'::jsonb, '公共设施', '整体满意度', '餐饮设施'),
('68027f2be3c98b0941765cae', '环境很好，是一家很有底蕴的酒店，还会再去的。
吃的餐厅也很好，值得品尝！
里面还有服装售卖，美发服务。', '["https://dimg04.c-ctrip.com/images/0236e12000c3recb36B35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000c3rea2rC74C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000c3reh87073B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000c3re7aiAF0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-10', '花园大床房', '大床房', '独自旅行', 51, 0, 1, 5, '["整体满意度","餐饮设施","周边配套"]'::jsonb, '整体满意度', '餐饮设施', '周边配套'),
('68027f2be3c98b0941765caf', '出差必住酒店 位置好', '["https://dimg04.c-ctrip.com/images/0230y12000cnz008h5FF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-01', '花园双床房', '双床房', '商务出差', 10, 0, 115, 3, '["交通便利性","整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL),
('68027f36e3c98b0941765cb0', '花园景色优美，服务优良，不愧是老牌五星级酒店～ 很多外国人，也是一景～ 酒店的性价比不错，还包括了两个早餐～', '["https://dimg04.c-ctrip.com/images/0236d12000c1sf5ujF957_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000c1sgl0d4532_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000c1skaf70D1F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-01', '花园双床房', '双床房', '家庭亲子', 54, 0, 6, 6, '["整体满意度","性价比","景观/朝向"]'::jsonb, '整体满意度', '性价比', '景观/朝向'),
('68027f36e3c98b0941765cb1', '房间很好，卫生很好。环境一流。
服务：也特别好。四十余年的历史底蕴，不愧是中国前三的酒店。下次出现还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0232s12000c16hu6v3CDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000c16jxyq6E0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000c16owj36056_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-30', '花园大床房', '大床房', '家庭亲子', 57, 0, 1, 6, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027f36e3c98b0941765cb2', '很满意！原以为酒店很老旧，设施不够好，事实上并非如此。可见酒店在维护方面功夫到位。交通很便利，出门就是地铁站，大堂很气派，餐厅多，人气旺。住了两天，都在酒店用餐，日式餐厅还没来得及享用。另外，赠送的酒店博物馆也很值得一逛。
提一点不足之处，抽水马桶可以加一个智能座圈，淋浴下水略有不畅。
希望花园酒店越来越好！', '["https://dimg04.c-ctrip.com/images/0233w12000bhu3dmwB53D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000bhtzb0g2E4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000bhtvngiE737_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000bhtyfshB396_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000bhtzrdwF418_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000bhu4qss2A05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000bhtyu2d1D45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000bhu0ruxDA89_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000bhu2ppj45D5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-25', '红棉大床套房', '套房', '家庭亲子', 155, 0, 35, 9, '["交通便利性","整体满意度","房间设施"]'::jsonb, '交通便利性', '整体满意度', '房间设施'),
('68027f36e3c98b0941765cb3', '一年大概要来广州七八次，每次来广州必住花园酒店，酒店的服务环境我认为一直是最好的，尤其给Viria、kristy两位女士，大大的好评，服务非常的令人满意，亲切，更体现出来了包容城市-广州，万分推荐', '["https://dimg04.c-ctrip.com/images/0236a12000bi64ejuDAC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-26', '花园双床房', '双床房', '商务出差', 98, 0, 2, 8, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027f36e3c98b0941765cb4', '是老牌五星酒店，床挺舒服，细节都做的很好。除了洗手间不太符合我的想象。', '["https://dimg04.c-ctrip.com/images/0235l12000cc49gezE1F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 35, 0, 8, 6, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL)
 ON CONFLICT (_id) DO NOTHING;
